from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'

# In-memory storage (use a database in production)
users_db = {
    'admin': {
        'password_hash': hashlib.sha256('admin123'.encode()).hexdigest(),
        'name': 'Admin User'
    },
    'john': {
        'password_hash': hashlib.sha256('john123'.encode()).hexdigest(),
        'name': 'John Doe'
    }
}

# Token storage: token -> {username, created_at, expires_at}
tokens_db = {}


def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()


def generate_token():
    return secrets.token_hex(32)


def cleanup_expired_tokens():
    """Remove expired tokens from storage."""
    now = datetime.utcnow()
    expired = [token for token, data in tokens_db.items() if data['expires_at'] < now]
    for token in expired:
        del tokens_db[token]


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check for token in Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header:
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        # Also check query parameter as fallback
        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({
                'success': False,
                'message': 'Authentication token is missing. Provide it via Authorization: Bearer <token> header.'
            }), 401

        # Cleanup expired tokens
        cleanup_expired_tokens()

        # Validate token
        token_data = tokens_db.get(token)
        if not token_data:
            return jsonify({
                'success': False,
                'message': 'Token is invalid or has expired.'
            }), 401

        if token_data['expires_at'] < datetime.utcnow():
            del tokens_db[token]
            return jsonify({
                'success': False,
                'message': 'Token has expired. Please login again.'
            }), 401

        # Pass current user info to the route
        current_user = {
            'username': token_data['username'],
            'name': users_db[token_data['username']]['name']
        }

        return f(current_user, *args, **kwargs)

    return decorated


@app.route('/', methods=['GET'])
def home():
    return jsonify({
        'message': 'Welcome to the Token Authentication API',
        'endpoints': {
            'POST /register': 'Register a new user (username, password, name)',
            'POST /login': 'Login and receive a token (username, password)',
            'POST /logout': 'Logout and invalidate token (requires token)',
            'GET /protected': 'Access protected resource (requires token)',
            'GET /profile': 'Get user profile (requires token)',
            'GET /users': 'List all users (requires token)',
        }
    })


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()

    if not data:
        return jsonify({'success': False, 'message': 'Request body must be JSON.'}), 400

    username = data.get('username')
    password = data.get('password')
    name = data.get('name')

    if not username or not password:
        return jsonify({'success': False, 'message': 'Username and password are required.'}), 400

    if username in users_db:
        return jsonify({'success': False, 'message': 'Username already exists.'}), 409

    if len(password) < 6:
        return jsonify({'success': False, 'message': 'Password must be at least 6 characters.'}), 400

    users_db[username] = {
        'password_hash': hash_password(password),
        'name': name or username
    }

    return jsonify({
        'success': True,
        'message': f'User "{username}" registered successfully.'
    }), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()

    if not data:
        return jsonify({'success': False, 'message': 'Request body must be JSON.'}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({'success': False, 'message': 'Username and password are required.'}), 400

    user = users_db.get(username)
    if not user or user['password_hash'] != hash_password(password):
        return jsonify({'success': False, 'message': 'Invalid username or password.'}), 401

    # Generate token
    token = generate_token()
    expires_at = datetime.utcnow() + timedelta(hours=24)

    tokens_db[token] = {
        'username': username,
        'created_at': datetime.utcnow(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'message': 'Login successful.',
        'token': token,
        'expires_at': expires_at.isoformat(),
        'user': {
            'username': username,
            'name': user['name']
        }
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user):
    # Find and remove the token
    auth_header = request.headers.get('Authorization')
    if auth_header:
        parts = auth_header.split()
        if len(parts) == 2:
            token = parts[1]
            if token in tokens_db:
                del tokens_db[token]

    return jsonify({
        'success': True,
        'message': 'Logged out successfully. Token has been invalidated.'
    }), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user):
    return jsonify({
        'success': True,
        'message': 'You have access to this protected endpoint!',
        'user': current_user,
        'data': {
            'secret_info': 'This is confidential data only visible to authenticated users.',
            'timestamp': datetime.utcnow().isoformat()
        }
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(current_user):
    username = current_user['username']
    user_data = users_db.get(username)

    # Count active tokens for this user
    active_sessions = sum(
        1 for data in tokens_db.values()
        if data['username'] == username and data['expires_at'] > datetime.utcnow()
    )

    return jsonify({
        'success': True,
        'profile': {
            'username': username,
            'name': user_data['name'],
            'active_sessions': active_sessions
        }
    }), 200


@app.route('/users', methods=['GET'])
@token_required
def list_users(current_user):
    user_list = [
        {'username': uname, 'name': udata['name']}
        for uname, udata in users_db.items()
    ]
    return jsonify({
        'success': True,
        'users': user_list,
        'total': len(user_list)
    }), 200


@app.route('/refresh', methods=['POST'])
@token_required
def refresh_token(current_user):
    """Refresh the current token by issuing a new one and invalidating the old."""
    # Invalidate old token
    auth_header = request.headers.get('Authorization')
    if auth_header:
        parts = auth_header.split()
        if len(parts) == 2:
            old_token = parts[1]
            if old_token in tokens_db:
                del tokens_db[old_token]

    # Generate new token
    new_token = generate_token()
    expires_at = datetime.utcnow() + timedelta(hours=24)

    tokens_db[new_token] = {
        'username': current_user['username'],
        'created_at': datetime.utcnow(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'message': 'Token refreshed successfully.',
        'token': new_token,
        'expires_at': expires_at.isoformat()
    }), 200


